// Check if name matches any brand SVG path
const brandIconPath = computed(() => {
  if (!props.name) return null
  const clean = props.name.toLowerCase().trim()
  if (brandSvgPaths[clean]) return brandSvgPaths[clean]
  if (clean === 'twitter / x' || clean === 'twitter/x') return brandSvgPaths.x
  if (clean === 'stack overflow' || clean === 'stackoverflow') return brandSvgPaths.stackoverflow
  if (clean === 'dev.to' || clean === 'devto') return brandSvgPaths.devto
  if (clean === 'buy me a coffee' || clean === 'buymeacoffee') return brandSvgPaths.buymeacoffee
  if (clean === 'ko-fi' || clean === 'kofi') return brandSvgPaths.kofi
  return null
})

// Alias map for technical/general Lucide components
const lucideAliases = {
  code: 'Code2',
  web: 'Code2',
  globe: 'Globe',
  network: 'Globe',
  shield: 'ShieldCheck',
  security: 'ShieldCheck',
  qa: 'ShieldCheck',
  testing: 'ShieldCheck',
  cpu: 'Cpu',
  hardware: 'Cpu',
  brain: 'BrainCircuit',
  ai: 'BrainCircuit',
  ml: 'BrainCircuit',
  server: 'Server',
  backend: 'Server',
  database: 'Database',
  db: 'Database',
  mobile: 'Smartphone',
  smartphone: 'Smartphone',
  cloud: 'Cloud',
  terminal: 'TerminalSquare',
  cli: 'Terminal',
  lock: 'Lock',
  wifi: 'Wifi',
  layers: 'Layers',
  monitor: 'Monitor',
  layout: 'Layout',
  filecode: 'FileCode',
  git: 'GitBranch',
  branch: 'GitBranch',
  wrench: 'Wrench',
  sparkles: 'Sparkles',
  boxes: 'Boxes',
  workflow: 'Workflow',
  mail: 'Mail',
  email: 'Mail',
  'email / mail': 'Mail',
  phone: 'Phone',
  tel: 'Phone',
  'phone / whatsapp': 'Phone',
  website: 'Globe',
  portfolio: 'Globe',
  'website lainnya': 'Globe',
  link: 'ExternalLink',
  notion: 'FileText',
  slack: 'MessageSquare',
  skype: 'PhoneCall',
  vercel: 'Triangle'
}

// Resolve to a Lucide icon component
const resolvedLucideIcon = computed(() => {
  if (!props.name) return null
  const clean = props.name.toLowerCase().trim()

  // 1. Check direct alias
  if (lucideAliases[clean] && LucideIcons[lucideAliases[clean]]) {
    return LucideIcons[lucideAliases[clean]]
  }

  // 2. Check exact name in LucideIcons
  if (LucideIcons[props.name]) {
    return LucideIcons[props.name]
  }

  // 3. Convert kebab/snake to PascalCase (e.g. terminal-square -> TerminalSquare)
  const pascal = clean
    .replace(/[-_]+/g, ' ')
    .split(' ')
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join('')

  if (LucideIcons[pascal]) {
    return LucideIcons[pascal]
  }

  return null
})
